package com.oyuki.wallet.entity; import com.oyuki.user.entity.User; import jakarta.persistence.*; import lombok.*; import java.math.BigDecimal; @Entity @Table(name="seller_wallets") @Getter @Setter @NoArgsConstructor @AllArgsConstructor @Builder public class SellerWallet { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @OneToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="user_id",unique=true) private User user; @Column(nullable=false,precision=15,scale=2) @Builder.Default private BigDecimal availableBalance=BigDecimal.ZERO; @Column(nullable=false,precision=15,scale=2) @Builder.Default private BigDecimal pendingBalance=BigDecimal.ZERO; @Column(length=120) private String bankName; @Column(length=30) private String accountNumber; @Column(length=150) private String accountName; }